package io.github.CyberTimon.RapidRAW

import android.os.Bundle
import android.webkit.WebView
import androidx.appcompat.app.AppCompatActivity

/**
 * Tauri Activity base class for Android.
 * In standard Tauri 2.x projects, this is generated by tauri-build.
 * Since we use a custom build setup, we define it here manually.
 */
open class TauriActivity : AppCompatActivity() {

    protected var webView: WebView? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
    }

    open fun onWebViewCreate(webView: WebView) {
        this.webView = webView
    }

    override fun onPause() {
        super.onPause()
    }

    override fun onResume() {
        super.onResume()
    }

    override fun onSaveInstanceState(outState: Bundle) {
        super.onSaveInstanceState(outState)
    }

    override fun onRestoreInstanceState(savedInstanceState: Bundle) {
        super.onRestoreInstanceState(savedInstanceState)
    }

    override fun onDestroy() {
        super.onDestroy()
    }
}